import React from 'react';
import { motion } from 'framer-motion';
import { CheckIcon } from '@heroicons/react/20/solid';

const plans = [
  {
    name: 'Listing Monitor',
    price: '$1,000',
    period: '/mo',
    desc: 'Full on-market coverage without the grunt work',
    popular: false,
    features: [
      'All major listing sites scraped daily',
      'Filtered to your exact criteria',
      'Outreach to matching sellers',
      'Meetings booked on your behalf',
    ],
    bestFor: 'Searchers who want full on-market coverage without the grunt work',
  },
  {
    name: 'Off-Market — State',
    price: '$3,000',
    period: '/mo',
    desc: 'Focused geographic mandate, deals nobody else sees',
    popular: true,
    features: [
      'Dedicated caller + email campaigns',
      'Direct outreach to owners in your state',
      'Off-market — sellers not listed anywhere',
      'Every response screened and qualified',
    ],
    bestFor: 'Searchers with a focused geographic mandate who want deals nobody else sees',
  },
  {
    name: 'Off-Market — National',
    price: '$5,000',
    period: '/mo',
    desc: 'Multi-state mandates with maximum volume',
    popular: false,
    features: [
      'Two dedicated callers + nationwide campaigns',
      'Direct owner outreach across multiple states',
      '20-50 qualified conversations per month',
      'Dedicated account manager',
    ],
    bestFor: 'Funds, family offices, and searchers with multi-state mandates',
  },
];

export default function Pricing() {
  return (
    <section id="pricing" className="py-20 lg:py-28">
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="text-center max-w-3xl mx-auto mb-16">
          <div className="inline-flex items-center gap-2 rounded-full bg-blue-500/10 border border-blue-500/20 px-4 py-1.5 mb-6">
            <span className="text-sm font-medium text-blue-400">Simple Pricing</span>
          </div>
          <h2 className="text-3xl sm:text-4xl lg:text-5xl font-bold">
            Choose Your Plan
          </h2>
          <p className="mt-4 text-lg text-gray-400">
            Every plan includes weekly reporting, dedicated support, and a custom acquisition criteria build. No long-term contracts.
          </p>
        </div>

        <div className="grid lg:grid-cols-3 gap-6 max-w-5xl mx-auto">
          {plans.map((plan, i) => (
            <motion.div
              key={plan.name}
              className={`relative rounded-2xl p-8 transition-all ${
                plan.popular
                  ? 'bg-gradient-to-b from-blue-500/10 to-blue-600/5 border-2 border-blue-500/30 ring-1 ring-blue-500/10'
                  : 'bg-white/[0.03] border border-white/[0.06] hover:border-white/10'
              }`}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: i * 0.1 }}
            >
              {plan.popular && (
                <div className="absolute -top-3.5 left-1/2 -translate-x-1/2">
                  <span className="inline-flex items-center rounded-full bg-blue-500 px-4 py-1 text-xs font-semibold text-white">
                    Most Popular
                  </span>
                </div>
              )}

              <div className="mb-6">
                <h3 className="text-lg font-bold text-white">{plan.name}</h3>
                <div className="mt-4 flex items-baseline gap-1">
                  <span className="text-4xl font-extrabold text-white">{plan.price}</span>
                  <span className="text-gray-500">{plan.period}</span>
                </div>
              </div>

              <ul className="space-y-3 mb-8">
                {plan.features.map((feature) => (
                  <li key={feature} className="flex items-start gap-3">
                    <CheckIcon className="h-5 w-5 text-blue-400 mt-0.5 shrink-0" />
                    <span className="text-sm text-gray-300">{feature}</span>
                  </li>
                ))}
              </ul>

              <div className="mb-6 py-3 px-4 rounded-xl bg-white/[0.03] border border-white/[0.04]">
                <p className="text-xs text-gray-500">
                  <span className="text-gray-400 font-medium">Best for:</span> {plan.bestFor}
                </p>
              </div>

              <a
                href="#cta"
                className={`block w-full rounded-full py-3 text-center text-sm font-semibold transition-all ${
                  plan.popular
                    ? 'bg-blue-500 text-white hover:bg-blue-400 shadow-lg shadow-blue-500/25'
                    : 'bg-white/5 text-white hover:bg-white/10 border border-white/10'
                }`}
              >
                Get Started
              </a>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}
